class Solution(object):
    def closestTarget(self, words, target, startIndex):
        n = len(words)
        min_dist = n
        for i in range(n):
            if words[i] == target:
                forward = (i - startIndex) % n
                backward = (startIndex - i) % n
                min_dist = min(min_dist, forward, backward)
        return min_dist if min_dist != n else -1
